# middleware/csrf.py
# CSRF Protection Middleware - TODO: implement custom CSRF protection
# This module should replace Django's built-in CSRF middleware
# with a double-submit cookie pattern suitable for SPA frontends.

from django.http import JsonResponse


class CSRFMiddleware:
    """Placeholder for custom CSRF middleware."""

    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        return self.get_response(request)

import pytest
from django.test import RequestFactory, override_settings
from middleware.csrf import CSRFMiddleware
import json


PLANBOARD_ALLOWED_ORIGINS = [
    'https://app.planboard.io',
    'https://staging.planboard.io',
    'https://localhost:3000',
]


@pytest.fixture
def csrf_middleware():
    def dummy_view(request):
        from django.http import JsonResponse
        return JsonResponse({'status': 'ok'})
    return CSRFMiddleware(dummy_view)


@pytest.fixture
def rf():
    return RequestFactory()


class TestCSRFTokenGeneration:
    """Test CSRF token generation and cookie setting."""

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_get_request_sets_csrf_cookie(self, csrf_middleware, rf):
        request = rf.get('/api/projects/')
        response = csrf_middleware(request)
        assert response.status_code == 200
        assert 'planboard_csrf' in response.cookies
        token = response.cookies['planboard_csrf'].value
        assert len(token) == 64  # 32 bytes hex-encoded

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_token_rotation_on_each_request(self, csrf_middleware, rf):
        request1 = rf.get('/api/projects/')
        response1 = csrf_middleware(request1)
        token1 = response1.cookies['planboard_csrf'].value

        request2 = rf.get('/api/projects/')
        request2.COOKIES['planboard_csrf'] = token1
        response2 = csrf_middleware(request2)
        token2 = response2.cookies['planboard_csrf'].value
        assert token1 != token2


class TestDoubleSubmitValidation:
    """Test cookie-to-header double submit validation."""

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_post_with_matching_token_succeeds(self, csrf_middleware, rf):
        token = 'a' * 64
        request = rf.post('/api/projects/', HTTP_X_CSRF_TOKEN=token,
                         HTTP_ORIGIN='https://app.planboard.io')
        request.COOKIES['planboard_csrf'] = token
        response = csrf_middleware(request)
        assert response.status_code == 200

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_post_with_mismatched_token_fails(self, csrf_middleware, rf):
        request = rf.post('/api/projects/', HTTP_X_CSRF_TOKEN='bad_token',
                         HTTP_ORIGIN='https://app.planboard.io')
        request.COOKIES['planboard_csrf'] = 'a' * 64
        response = csrf_middleware(request)
        assert response.status_code == 403
        body = json.loads(response.content)
        assert 'csrf' in body.get('error', '').lower()

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_post_without_csrf_header_fails(self, csrf_middleware, rf):
        request = rf.post('/api/projects/',
                         HTTP_ORIGIN='https://app.planboard.io')
        request.COOKIES['planboard_csrf'] = 'a' * 64
        response = csrf_middleware(request)
        assert response.status_code == 403

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_post_without_csrf_cookie_fails(self, csrf_middleware, rf):
        request = rf.post('/api/projects/', HTTP_X_CSRF_TOKEN='a' * 64,
                         HTTP_ORIGIN='https://app.planboard.io')
        response = csrf_middleware(request)
        assert response.status_code == 403


class TestOriginValidation:
    """Test Origin and Referer header validation."""

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_valid_origin_header_passes(self, csrf_middleware, rf):
        token = 'a' * 64
        request = rf.post('/api/projects/', HTTP_X_CSRF_TOKEN=token,
                         HTTP_ORIGIN='https://app.planboard.io')
        request.COOKIES['planboard_csrf'] = token
        response = csrf_middleware(request)
        assert response.status_code == 200

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_invalid_origin_header_fails(self, csrf_middleware, rf):
        token = 'a' * 64
        request = rf.post('/api/projects/', HTTP_X_CSRF_TOKEN=token,
                         HTTP_ORIGIN='https://evil.com')
        request.COOKIES['planboard_csrf'] = token
        response = csrf_middleware(request)
        assert response.status_code == 403

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_referer_fallback_when_no_origin(self, csrf_middleware, rf):
        token = 'a' * 64
        request = rf.post('/api/projects/', HTTP_X_CSRF_TOKEN=token,
                         HTTP_REFERER='https://app.planboard.io/dashboard/tasks')
        request.COOKIES['planboard_csrf'] = token
        response = csrf_middleware(request)
        assert response.status_code == 200

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_invalid_referer_fails(self, csrf_middleware, rf):
        token = 'a' * 64
        request = rf.post('/api/projects/', HTTP_X_CSRF_TOKEN=token,
                         HTTP_REFERER='https://evil.com/attack')
        request.COOKIES['planboard_csrf'] = token
        response = csrf_middleware(request)
        assert response.status_code == 403

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_no_origin_or_referer_fails(self, csrf_middleware, rf):
        token = 'a' * 64
        request = rf.post('/api/projects/', HTTP_X_CSRF_TOKEN=token)
        request.COOKIES['planboard_csrf'] = token
        response = csrf_middleware(request)
        assert response.status_code == 403


class TestExemptPaths:
    """Test CSRF-exempt paths."""

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_webhook_path_exempt(self, csrf_middleware, rf):
        request = rf.post('/api/webhooks/stripe')
        response = csrf_middleware(request)
        assert response.status_code == 200

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_public_path_exempt(self, csrf_middleware, rf):
        request = rf.post('/api/public/health')
        response = csrf_middleware(request)
        assert response.status_code == 200


class TestSafeMethods:
    """Test that safe HTTP methods skip CSRF validation."""

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_get_skips_csrf_check(self, csrf_middleware, rf):
        request = rf.get('/api/projects/')
        response = csrf_middleware(request)
        assert response.status_code == 200

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_head_skips_csrf_check(self, csrf_middleware, rf):
        request = rf.head('/api/projects/')
        response = csrf_middleware(request)
        assert response.status_code == 200

    @override_settings(PLANBOARD_ALLOWED_ORIGINS=PLANBOARD_ALLOWED_ORIGINS)
    def test_options_skips_csrf_check(self, csrf_middleware, rf):
        request = rf.options('/api/projects/')
        response = csrf_middleware(request)
        assert response.status_code == 200
